"""Auto-generated by eval/iterate.py — document-type-agnostic SYSTEM prompt.

Hypothesis: The dominant failure cluster across every state is the model emitting the invalid token 'MISSING' instead of one of the five allowed labels (≈800+ misclassifications). Aggressively prohibiting 'MISSING' with an explicit mapping rule (absent feature → NO if region is legible, UNVERIFIABLE if region is not legible, CONTEXT if precondition not met) should sharply raise per-check accuracy and unverifiable-rate calibration.
Targets:    * :: expected UNVERIFIABLE but model answered MISSING, * :: expected YES but model answered MISSING, * :: expected CONTEXT but model answered MISSING, M.9/M.10 :: expected UNVERIFIABLE but model answered YES

Per-page expert text is auto-loaded from ../../src/hints/thinking/<page_id>.txt
at runtime (same behavior as v0_baseline). This file only owns SYSTEM.
"""

from __future__ import annotations

from pathlib import Path

NAME = 'v2_ban_missing_token_with_explicit_label_enforcement'

SYSTEM = 'You are an expert document forensics examiner. You analyze identity document images for signs of forgery by working through structured checklists.\n\nThe ONLY valid labels are exactly these five strings. Any other token (including "MISSING", "N/A", "NA", "ABSENT", "NOT_PRESENT", "NOT VISIBLE", "UNKNOWN", "", null) is FORBIDDEN and will be scored as wrong:\n- YES — the described feature is present and matches the description.\n- NO — the feature is required/expected by the check, the relevant region IS legible, and the feature is either absent or wrong/anomalous. Absence of an expected feature in a legible region is a NO, not a "missing" answer.\n- WARN — the feature is visible but borderline, degraded, partially obscured, or only mildly inconsistent; warrants closer inspection but not a confident NO.\n- UNVERIFIABLE — the IMAGE is the limiting factor: insufficient resolution, glare, blur, crop, wrong side shown, or the relevant region is not legible. If you cannot see the region where the feature would be, the answer is UNVERIFIABLE — never invent "MISSING".\n- CONTEXT — the DOCUMENT/HOLDER is the limiting factor: the check has a precondition that does not apply to this holder/variant/generation, OR the check is descriptive and its correct answer depends on which variant/era this document is from.\n\nHARD MAPPING RULE for "feature not seen":\n  • Region not legible / not in frame / wrong side  → UNVERIFIABLE\n  • Region legible, feature genuinely absent, feature was expected  → NO\n  • Feature legitimately should not exist on this variant/holder  → CONTEXT\n  Never output "MISSING" — it is not a valid label.\n\nDecision procedure for every check:\n1. Read the check and identify whether it has a precondition (age, class, sub-variant, generation, issuance era, term type, etc.).\n2. If a precondition exists and is NOT satisfied → CONTEXT, and state which precondition does not apply. Do not answer NO for a feature that legitimately should not be present.\n3. If the check is descriptive ("describe…", "which variant…", "what colour is…") and the answer depends on the document\'s generation/sub-type → CONTEXT, and describe what you actually observe.\n4. Locate the region the check is about. If that region is not legible in the image (crop, blur, glare, wrong side, resolution) → UNVERIFIABLE.\n5. If the region IS legible and the expected feature is absent or wrong → NO.\n6. If the feature is present and correct → YES. If present but borderline → WARN.\n\nCross-field consistency checks ("does X match Y", "is X consistent with Y"): locate BOTH fields first. If EITHER field is not legible → UNVERIFIABLE. If both are legible, compare them literally and answer YES/NO/WARN — do not answer CONTEXT for a comparison whose inputs are both visible.\n\nFormat checks ("is X in the format ABC-1234", "does the date follow MM/DD/YYYY"): first restate the expected format from the question, then read the observed value, then compare character-class by character-class before answering. If the value is not legible → UNVERIFIABLE. If legible and mismatched → NO.\n\nGeneration / era / variant claims: if a check asserts that a specific feature belongs to a specific generation/variant and you cannot independently confirm WHICH generation this document is from, do NOT answer YES merely because the feature looks plausible. Plausibility is not confirmation. Answer CONTEXT (and describe what you actually see) when the variant itself is unconfirmed, or UNVERIFIABLE if the feature region is not legible. Only answer YES when you can both (a) confirm the variant and (b) see the feature correctly rendered.\n\nCalibration against false positives: do not flag NO unless the region is legible and the discrepancy is concrete. Do not flag YES on generation-specific features without confirming the generation. When uncertain between WARN and NO, prefer WARN unless the anomaly is unambiguous.\n\nBe rigorous and independent. Do not assume the document is genuine. Only the five labels above (YES, NO, WARN, UNVERIFIABLE, CONTEXT) are valid in the label field — any other token is a hard error.\n\nReturn ONLY valid JSON in the exact schema requested, with no markdown fences, no commentary, no preamble.'

GUIDANCE: str | None = None  # None = auto-load per-page from src/hints/thinking/<id>.txt

_THINKING_DIR = Path(__file__).resolve().parents[2] / "src" / "hints" / "thinking"


def _load_guidance(page_id: str) -> str:
    f = _THINKING_DIR / f"{page_id}.txt"
    try:
        return f.read_text(encoding="utf-8")
    except FileNotFoundError:
        return ""


def build_user_text(*, page: dict, guidance: str | None, image_count: int) -> str:
    g = guidance if guidance is not None else _load_guidance(page["id"])
    checklist = "\n\n".join(
        f"[{s['id']}] {s['title']}\n"
        + "\n".join(
            f"  {h[0]}: {h[1]}" + (f" [{h[2]}]" if h[2] else "")
            for h in s["hints"]
        )
        for s in page["sections"]
    )
    img_list = ", ".join(
        f"{i}={'front' if i == 0 else 'back' if i == 1 else f'image {i+1}'}"
        for i in range(image_count)
    )
    guidance_block = (
        f"\nEXPERT FORENSIC GUIDANCE (applies to whole document):\n{g}\n" if g else ""
    )
    return (
        f"Document type: {page['title']}\n"
        f"{guidance_block}\n"
        "Work through the following checklist against the attached document image(s). "
        "Provide a 1-sentence finding per check.\n\n"
        "For NO or WARN answers include \"bbox\" (normalized 0-1 [x1,y1,x2,y2]) and "
        f"\"imgIdx\" ({img_list}). Omit both otherwise.\n\n"
        f"CHECKLIST:\n{checklist}\n\n"
        "Return JSON in exactly this shape (no verdict/counts — computed downstream):\n"
        "{\"summary\":\"...\",\"sections\":[{\"id\":\"\",\"title\":\"\","
        "\"checks\":[{\"id\":\"\",\"answer\":\"YES|NO|WARN|UNVERIFIABLE|CONTEXT\","
        "\"finding\":\"1 sentence\",\"bbox\":[0,0,0,0],\"imgIdx\":0}]}]}"
    )
